var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`NINA_FRONTIER_NULL_NULL`,text:{KOREA:`해고 통보라면 비비 꼬지 말고 빨리 끝내 줘. 쫓겨나는 건 이제 익숙하거든.`,JPN:`解雇通知なら、回りくどいやり方じゃなく、さっさと済ませてくれ。追い出されることに慣れてるんだ。`,ENG:`If you want to fire me, just say it. I'm used to getting kicked out.`,TWN:`是解僱通知的話就別拖拖拉拉的，快點結束吧。我已經很習慣被趕走了。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`NINA_FRONTIER_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`NINA_FRONTIER_NULL_NULL`,text:{KOREA:`......뭐? 종신 계약 때문에 부른 거라고?`,JPN:`……何？　終身契約をするために呼んだだと？`,ENG:`What? You called me because you wanted to hire me for life?`,TWN:`……什麼？是為了終身契約才叫我的？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`NINA_FRONTIER_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`NINA_FRONTIER_NULL_NULL`,text:{KOREA:`아니, 잠깐 기다려.`,JPN:`いや、ちょっと待ってくれ。`,ENG:`Wait a minute.`,TWN:`不，稍等一下。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`NINA_FRONTIER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`NINA_FRONTIER_NULL_NULL`,text:{KOREA:`네가 우리 같은 삼류에게도 잘 대해 준다는 건 알고 있어. 하지만 회사 일이란 게 인정으로만 돌아가는 건 아니잖아.`,JPN:`社長が私たちのような貧困層によくしてくれてることは知っている。だが、会社は善意だけで回らないはずだ。`,ENG:`I know you are generous to even third-rate mercenaries like us. But caring about us is one thing; running a company is another.`,TWN:`我知道你對我們這種三流角色也很好。但公司不是靠人情就能經營的吧？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`NINA_FRONTIER_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`NINA_FRONTIER_NULL_NULL`,text:{KOREA:`......그간의 노력에 대한 보답이라니.`,JPN:`……これまでの努力に対するお礼なのか。`,ENG:`You want to reward me for my hard work so far?`,TWN:`……居然說是對我之前努力的回報。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`NINA_FRONTIER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`NINA_FRONTIER_NULL_NULL`,text:{KOREA:`내가 기대할 수 있었던 건......기껏 해봐야 정규직 정도였는데 말이야......`,JPN:`私が期待できたのは……せいぜい正社員くらいだったのにな……`,ENG:`I thought I'd be lucky if I got a full-time position...`,TWN:`我能期待的……最多就只是正式員工而已……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`NINA_FRONTIER_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`NINA_FRONTIER_NULL_NULL`,text:{KOREA:`미안. 튕기는 시늉이라도 하고 싶은데, 사양하는 건 서투르네.`,JPN:`すまない。一度断るふりでもしたいが、遠慮するのが苦手なんだ。`,ENG:`Sorry. I'm not good at saying no, even as a joke.`,TWN:`抱歉。雖然我想假裝拒絕，但實在無法推辭呢。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`NINA_FRONTIER_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`NINA_FRONTIER_NULL_NULL`,text:{KOREA:`......잘 부탁해. 사장님.`,JPN:`……よろしく頼むよ、社長。`,ENG:`Thank you for choosing me, Boss.`,TWN:`……請多指教，老闆。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`NINA_FRONTIER_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};